1	import './style.css';
2	
3	const SVG_NS = 'http://www.w3.org/2000/svg';
4	const MIN_WIDTH = 1;
5	const MAX_WIDTH = 200;
6	const BRUSH_STRENGTH = 2;
7	const SAMPLE_MIN_DIST = 1.5;
8	const MAX_HISTORY = 50;
9	const FILE_VERSION = 1;
10	
11	type Tool = 'pen' | 'width' | 'select';
12	type RenderMode = 'catmull' | 'quadratic';
13	type Point = { x: number; y: number };
14	type Sample = Point & { w: number };
15	type Stroke = { color: string; samples: Sample[]; el: SVGPathElement; renderMode: RenderMode };
16	type Snapshot = { color: string; samples: Sample[]; renderMode: RenderMode }[];
17	type HandleHit = { stroke: Stroke; index: number };
18	type NodeDrag = {
19	  stroke: Stroke;
20	  index: number;
21	  origPositions: Point[];
22	  arcDists: number[];
23	  startPoint: Point;
24	};
25	
26	const svg = document.getElementById('canvas') as unknown as SVGSVGElement;
27	const widthInput = document.getElementById('width') as HTMLInputElement;
28	const brushInput = document.getElementById('brush') as HTMLInputElement;
29	const colorInput = document.getElementById('color') as HTMLInputElement;
30	const clearBtn = document.getElementById('clear') as HTMLButtonElement;
31	const exportBtn = document.getElementById('export') as HTMLButtonElement;
32	const saveBtn = document.getElementById('save') as HTMLButtonElement;
33	const loadBtn = document.getElementById('load') as HTMLButtonElement;
34	const toolPenBtn = document.getElementById('tool-pen') as HTMLButtonElement;
35	const toolWidthBtn = document.getElementById('tool-width') as HTMLButtonElement;
36	const toolSelectBtn = document.getElementById('tool-select') as HTMLButtonElement;
37	const undoBtn = document.getElementById('undo') as HTMLButtonElement;
38	const redoBtn = document.getElementById('redo') as HTMLButtonElement;
39	const brushCursor = document.getElementById('brush-cursor') as HTMLDivElement;
40	const selectionRect = document.getElementById('selection-rect') as HTMLDivElement;
41	const strokeOptions = document.getElementById('stroke-options') as HTMLDivElement;
42	const renderModeRadios = document.querySelectorAll<HTMLInputElement>('input[name="render-mode"]');
43	
44	const state = {
45	  tool: 'pen' as Tool,
46	  strokes: [] as Stroke[],
47	  current: null as Stroke | null,
48	  brushing: false,
49	  selected: null as Stroke | null,
50	  dragging: false,
51	  dragLast: null as Point | null,
52	  draggingNode: null as NodeDrag | null,
53	  baseWidth: Number(widthInput.value),
54	  brushRadius: Number(brushInput.value),
55	  color: colorInput.value,
56	};
57	
58	const undoStack: Snapshot[] = [];
59	const redoStack: Snapshot[] = [];
60	const handleByEl = new Map<SVGCircleElement, HandleHit>();
61	let handleGroup: SVGGElement | null = null;
62	
63	main();
64	
65	function main() {
66	  syncCanvasSize();
67	  window.addEventListener('resize', syncCanvasSize);
68	
69	  widthInput.addEventListener('input', () => {
70	    state.baseWidth = Number(widthInput.value);
71	  });
72	  brushInput.addEventListener('input', () => {
73	    state.brushRadius = Number(brushInput.value);
74	  });
75	  colorInput.addEventListener('input', () => {
76	    state.color = colorInput.value;
77	  });
78	  clearBtn.addEventListener('click', clearAll);
79	  exportBtn.addEventListener('click', exportSvg);
80	  saveBtn.addEventListener('click', saveFile);
81	  loadBtn.addEventListener('click', loadFile);
82	  toolPenBtn.addEventListener('click', () => setTool('pen'));
83	  toolWidthBtn.addEventListener('click', () => setTool('width'));
84	  toolSelectBtn.addEventListener('click', () => setTool('select'));
85	  undoBtn.addEventListener('click', undo);
86	  redoBtn.addEventListener('click', redo);
87	  renderModeRadios.forEach((r) => r.addEventListener('change', onRenderModeChange));
88	
89	  document.addEventListener('keydown', onKeyDown);
90	
91	  svg.addEventListener('pointerdown', onPointerDown);
92	  svg.addEventListener('pointermove', onPointerMove);
93	  svg.addEventListener('pointerup', onPointerUp);
94	  svg.addEventListener('pointercancel', onPointerUp);
95	  svg.addEventListener('pointerleave', () => {
96	    brushCursor.style.display = 'none';
97	  });
98	}
99	
100	function onPointerDown(e: PointerEvent) {
101	  svg.setPointerCapture(e.pointerId);
102	  if (state.tool === 'pen') penDown(e);
103	  else if (state.tool === 'width') widthDown(e);
104	  else selectDown(e);
105	}
106	
107	function onPointerMove(e: PointerEvent) {
108	  updateBrushCursor(e);
109	  if (state.tool === 'pen') penMove(e);
110	  else if (state.tool === 'width') widthMove(e);
111	  else selectMove(e);
112	}
113	
114	function onPointerUp(e: PointerEvent) {
115	  if (svg.hasPointerCapture(e.pointerId)) svg.releasePointerCapture(e.pointerId);
116	  state.current = null;
117	  state.brushing = false;
118	  selectUp();
119	}
120	
121	function onKeyDown(e: KeyboardEvent) {
122	  if (e.target instanceof HTMLInputElement) return;
123	  const mod = e.metaKey || e.ctrlKey;
124	  if (mod && e.key.toLowerCase() === 'z') {
125	    e.preventDefault();
126	    if (e.shiftKey) redo();
127	    else undo();
128	    return;
129	  }
130	  if (mod && e.key.toLowerCase() === 'y') {
131	    e.preventDefault();
132	    redo();
133	    return;
134	  }
135	  if ((e.key === 'Delete' || e.key === 'Backspace') && state.selected) {
136	    e.preventDefault();
137	    deleteSelected();
138	    return;
139	  }
140	  if (e.key === 'p') setTool('pen');
141	  else if (e.key === 'w') setTool('width');
142	  else if (e.key === 's') setTool('select');
143	}
144	
145	function setTool(t: Tool) {
146	  state.tool = t;
147	  toolPenBtn.classList.toggle('active', t === 'pen');
148	  toolWidthBtn.classList.toggle('active', t === 'width');
149	  toolSelectBtn.classList.toggle('active', t === 'select');
150	  svg.classList.toggle('tool-select', t === 'select');
151	  if (t !== 'width') brushCursor.style.display = 'none';
152	  if (t !== 'select') deselect();
153	}
154	
155	function penDown(e: PointerEvent) {
156	  pushHistory();
157	  const el = document.createElementNS(SVG_NS, 'path');
158	  el.setAttribute('fill', state.color);
159	  const stroke: Stroke = {
160	    color: state.color,
161	    samples: [sampleFromEvent(e)],
162	    el,
163	    renderMode: 'catmull',
164	  };
165	  el.setAttribute('d', strokeToPathD(stroke));
166	  svg.appendChild(el);
167	  state.strokes.push(stroke);
168	  state.current = stroke;
169	}
170	
171	function penMove(e: PointerEvent) {
172	  if (!state.current) return;
173	  const stroke = state.current;
174	  const events = e.getCoalescedEvents?.() ?? [e];
175	  let changed = false;
176	  for (const ev of events.length > 0 ? events : [e]) {
177	    const sample = sampleFromEvent(ev);
178	    const last = stroke.samples[stroke.samples.length - 1];
179	    if (distance(last, sample) < SAMPLE_MIN_DIST) continue;
180	    stroke.samples.push(sample);
181	    changed = true;
182	  }
183	  if (changed) stroke.el.setAttribute('d', strokeToPathD(stroke));
184	}
185	
186	function selectDown(e: PointerEvent) {
187	  const target = e.target;
188	  if (target instanceof SVGCircleElement) {
189	    const hit = handleByEl.get(target);
190	    if (hit) {
191	      selectStroke(hit.stroke);
192	      pushHistory();
193	      state.draggingNode = {
194	        stroke: hit.stroke,
195	        index: hit.index,
196	        origPositions: hit.stroke.samples.map((s) => ({ x: s.x, y: s.y })),
197	        arcDists: computeArcDistances(hit.stroke.samples, hit.index),
198	        startPoint: canvasPoint(e),
199	      };
200	      svg.classList.add('dragging');
201	      return;
202	    }
203	  }
204	  if (target instanceof SVGPathElement) {
205	    const stroke = state.strokes.find((s) => s.el === target);
206	    if (stroke) {
207	      selectStroke(stroke);
208	      pushHistory();
209	      state.dragging = true;
210	      state.dragLast = canvasPoint(e);
211	      svg.classList.add('dragging');
212	      return;
213	    }
214	  }
215	  deselect();
216	}
217	
218	function selectMove(e: PointerEvent) {
219	  if (state.draggingNode) {
220	    dragNode(state.draggingNode, canvasPoint(e));
221	    return;
222	  }
223	  if (state.dragging && state.selected && state.dragLast) {
224	    const now = canvasPoint(e);
225	    const dx = now.x - state.dragLast.x;
226	    const dy = now.y - state.dragLast.y;
227	    state.dragLast = now;
228	    translateStroke(state.selected, dx, dy);
229	    state.selected.el.setAttribute('d', strokeToPathD(state.selected));
230	    refreshHandlePositions(state.selected);
231	    updateSelectionRect();
232	  }
233	}
234	
235	function selectUp() {
236	  state.dragging = false;
237	  state.dragLast = null;
238	  state.draggingNode = null;
239	  svg.classList.remove('dragging');
240	  if (state.tool !== 'width') brushCursor.style.display = 'none';
241	}
242	
243	function selectStroke(stroke: Stroke) {
244	  if (state.selected === stroke) return;
245	  state.selected = stroke;
246	  buildHandles(stroke);
247	  updateSelectionRect();
248	}
249	
250	function deselect() {
251	  if (!state.selected) return;
252	  state.selected = null;
253	  clearHandles();
254	  updateSelectionRect();
255	}
256	
257	function dragNode(drag: NodeDrag, p: Point) {
258	  const sigma = Math.max(1, state.brushRadius);
259	  const dx = p.x - drag.startPoint.x;
260	  const dy = p.y - drag.startPoint.y;
261	  for (let i = 0; i < drag.stroke.samples.length; i++) {
262	    const weight = Math.exp(-((drag.arcDists[i] / sigma) ** 2));
263	    drag.stroke.samples[i].x = drag.origPositions[i].x + dx * weight;
264	    drag.stroke.samples[i].y = drag.origPositions[i].y + dy * weight;
265	  }
266	  drag.stroke.el.setAttribute('d', strokeToPathD(drag.stroke));
267	  refreshHandlePositions(drag.stroke);
268	  updateSelectionRect();
269	}
270	
271	function computeArcDistances(samples: Sample[], from: number): number[] {
272	  const N = samples.length;
273	  const dists = new Array<number>(N).fill(0);
274	  for (let j = from + 1; j < N; j++) {
275	    dists[j] = dists[j - 1] + distance(samples[j - 1], samples[j]);
276	  }
277	  for (let j = from - 1; j >= 0; j--) {
278	    dists[j] = dists[j + 1] + distance(samples[j + 1], samples[j]);
279	  }
280	  return dists;
281	}
282	
283	function buildHandles(stroke: Stroke) {
284	  clearHandles();
285	  const g = ensureHandleGroup();
286	  for (let i = 0; i < stroke.samples.length; i++) {
287	    const s = stroke.samples[i];
288	    const c = document.createElementNS(SVG_NS, 'circle');
289	    c.setAttribute('cx', String(s.x));
290	    c.setAttribute('cy', String(s.y));
291	    c.setAttribute('r', '4');
292	    c.setAttribute('fill', '#fff');
293	    c.setAttribute('stroke', '#0a84ff');
294	    c.setAttribute('stroke-width', '1.5');
295	    c.setAttribute('class', 'handle');
296	    g.appendChild(c);
297	    handleByEl.set(c, { stroke, index: i });
298	  }
299	}
300	
301	function refreshHandlePositions(stroke: Stroke) {
302	  if (state.selected !== stroke || !handleGroup) return;
303	  const circles = handleGroup.children;
304	  if (circles.length !== stroke.samples.length) {
305	    buildHandles(stroke);
306	    return;
307	  }
308	  for (let i = 0; i < circles.length; i++) {
309	    const c = circles[i] as SVGCircleElement;
310	    c.setAttribute('cx', String(stroke.samples[i].x));
311	    c.setAttribute('cy', String(stroke.samples[i].y));
312	  }
313	}
314	
315	function clearHandles() {
316	  handleByEl.clear();
317	  if (handleGroup) handleGroup.replaceChildren();
318	}
319	
320	function ensureHandleGroup(): SVGGElement {
321	  if (handleGroup && handleGroup.isConnected) return handleGroup;
322	  handleGroup = document.createElementNS(SVG_NS, 'g');
323	  handleGroup.setAttribute('id', 'handles');
324	  svg.appendChild(handleGroup);
325	  return handleGroup;
326	}
327	
328	function translateStroke(stroke: Stroke, dx: number, dy: number) {
329	  for (const s of stroke.samples) {
330	    s.x += dx;
331	    s.y += dy;
332	  }
333	}
334	
335	function deleteSelected() {
336	  if (!state.selected) return;
337	  pushHistory();
338	  const i = state.strokes.indexOf(state.selected);
339	  if (i >= 0) state.strokes.splice(i, 1);
340	  state.selected.el.remove();
341	  deselect();
342	}
343	
344	function updateSelectionRect() {
345	  if (!state.selected) {
346	    selectionRect.style.display = 'none';
347	    strokeOptions.style.display = 'none';
348	    return;
349	  }
350	  const { minX, minY, maxX, maxY } = strokeBbox(state.selected);
351	  selectionRect.style.display = 'block';
352	  selectionRect.style.left = `${minX}px`;
353	  selectionRect.style.top = `${minY}px`;
354	  selectionRect.style.width = `${maxX - minX}px`;
355	  selectionRect.style.height = `${maxY - minY}px`;
356	  strokeOptions.style.display = 'flex';
357	  strokeOptions.style.left = `${minX}px`;
358	  strokeOptions.style.top = `${maxY + 8}px`;
359	  renderModeRadios.forEach((r) => {
360	    r.checked = r.value === state.selected!.renderMode;
361	  });
362	}
363	
364	function onRenderModeChange(e: Event) {
365	  if (!state.selected) return;
366	  const value = (e.target as HTMLInputElement).value as RenderMode;
367	  if (state.selected.renderMode === value) return;
368	  pushHistory();
369	  state.selected.renderMode = value;
370	  state.selected.el.setAttribute('d', strokeToPathD(state.selected));
371	}
372	
373	function strokeBbox(stroke: Stroke): { minX: number; minY: number; maxX: number; maxY: number } {
374	  let minX = Infinity;
375	  let minY = Infinity;
376	  let maxX = -Infinity;
377	  let maxY = -Infinity;
378	  for (const s of stroke.samples) {
379	    const r = s.w / 2;
380	    if (s.x - r < minX) minX = s.x - r;
381	    if (s.x + r > maxX) maxX = s.x + r;
382	    if (s.y - r < minY) minY = s.y - r;
383	    if (s.y + r > maxY) maxY = s.y + r;
384	  }
385	  return { minX, minY, maxX, maxY };
386	}
387	
388	function widthDown(e: PointerEvent) {
389	  pushHistory();
390	  state.brushing = true;
391	  applyBrush(canvasPoint(e), e.shiftKey);
392	}
393	
394	function widthMove(e: PointerEvent) {
395	  if (!state.brushing) return;
396	  applyBrush(canvasPoint(e), e.shiftKey);
397	}
398	
399	function applyBrush(p: Point, shrink: boolean) {
400	  const delta = shrink ? -BRUSH_STRENGTH : BRUSH_STRENGTH;
401	  for (const stroke of state.strokes) {
402	    let touched = false;
403	    for (const s of stroke.samples) {
404	      const d = distance(p, s);
405	      if (d > state.brushRadius) continue;
406	      const falloff = 1 - d / state.brushRadius;
407	      s.w = clamp(s.w + delta * falloff, MIN_WIDTH, MAX_WIDTH);
408	      touched = true;
409	    }
410	    if (touched) stroke.el.setAttribute('d', strokeToPathD(stroke));
411	  }
412	}
413	
414	function updateBrushCursor(e: PointerEvent) {
415	  const visible = state.tool === 'width' || state.draggingNode !== null;
416	  if (!visible) {
417	    brushCursor.style.display = 'none';
418	    return;
419	  }
420	  const size = state.brushRadius * 2;
421	  brushCursor.style.display = 'block';
422	  brushCursor.style.left = `${e.clientX}px`;
423	  brushCursor.style.top = `${e.clientY}px`;
424	  brushCursor.style.width = `${size}px`;
425	  brushCursor.style.height = `${size}px`;
426	}
427	
428	function sampleFromEvent(e: PointerEvent): Sample {
429	  const { x, y } = canvasPoint(e);
430	  return { x, y, w: effectiveWidth(e) };
431	}
432	
433	function canvasPoint(e: PointerEvent): Point {
434	  const rect = svg.getBoundingClientRect();
435	  return { x: e.clientX - rect.left, y: e.clientY - rect.top };
436	}
437	
438	function effectiveWidth(e: PointerEvent): number {
439	  const hasPressure = e.pointerType !== 'mouse' && e.pressure > 0 && e.pressure !== 0.5;
440	  return hasPressure ? state.baseWidth * e.pressure * 2 : state.baseWidth;
441	}
442	
443	function strokeToPathD(stroke: Stroke): string {
444	  const { samples } = stroke;
445	  if (samples.length === 0) return '';
446	  if (samples.length === 1) return dotPath(samples[0]);
447	  return ribbonPath(stroke);
448	}
449	
450	function dotPath(s: Sample): string {
451	  const r = s.w / 2;
452	  return (
453	    `M ${s.x - r} ${s.y}` +
454	    ` A ${r} ${r} 0 1 0 ${s.x + r} ${s.y}` +
455	    ` A ${r} ${r} 0 1 0 ${s.x - r} ${s.y} Z`
456	  );
457	}
458	
459	function ribbonPath(stroke: Stroke): string {
460	  const samples = stroke.samples;
461	  const { left, right } = offsetRails(samples);
462	  const startR = samples[0].w / 2;
463	  const endR = samples[samples.length - 1].w / 2;
464	  const reversedRight = [...right].reverse();
465	  const smooth = stroke.renderMode === 'catmull' ? smoothRailCatmull : smoothRailQuadratic;
466	  const parts: string[] = [`M ${left[0].x} ${left[0].y}`];
467	  parts.push(smooth(left));
468	  parts.push(`A ${endR} ${endR} 0 0 0 ${right[right.length - 1].x} ${right[right.length - 1].y}`);
469	  parts.push(smooth(reversedRight));
470	  parts.push(`A ${startR} ${startR} 0 0 0 ${left[0].x} ${left[0].y}`);
471	  parts.push('Z');
472	  return parts.join(' ');
473	}
474	
475	function smoothRailCatmull(pts: Point[]): string {
476	  if (pts.length < 2) return '';
477	  if (pts.length === 2) return `L ${pts[1].x} ${pts[1].y}`;
478	  const cmds: string[] = [];
479	  const n = pts.length;
480	  for (let i = 0; i < n - 1; i++) {
481	    const p0 = i > 0 ? pts[i - 1] : pts[i];
482	    const p1 = pts[i];
483	    const p2 = pts[i + 1];
484	    const p3 = i + 2 < n ? pts[i + 2] : pts[i + 1];
485	    const c1x = p1.x + (p2.x - p0.x) / 6;
486	    const c1y = p1.y + (p2.y - p0.y) / 6;
487	    const c2x = p2.x - (p3.x - p1.x) / 6;
488	    const c2y = p2.y - (p3.y - p1.y) / 6;
489	    cmds.push(`C ${c1x} ${c1y} ${c2x} ${c2y} ${p2.x} ${p2.y}`);
490	  }
491	  return cmds.join(' ');
492	}
493	
494	function smoothRailQuadratic(pts: Point[]): string {
495	  if (pts.length < 2) return '';
496	  if (pts.length === 2) return `L ${pts[1].x} ${pts[1].y}`;
497	  const cmds: string[] = [];
498	  const m0x = (pts[0].x + pts[1].x) / 2;
499	  const m0y = (pts[0].y + pts[1].y) / 2;
500	  cmds.push(`L ${m0x} ${m0y}`);
501	  for (let i = 1; i < pts.length - 1; i++) {
502	    const mx = (pts[i].x + pts[i + 1].x) / 2;
503	    const my = (pts[i].y + pts[i + 1].y) / 2;
504	    cmds.push(`Q ${pts[i].x} ${pts[i].y} ${mx} ${my}`);
505	  }
506	  cmds.push(`L ${pts[pts.length - 1].x} ${pts[pts.length - 1].y}`);
507	  return cmds.join(' ');
508	}
509	
510	function offsetRails(samples: Sample[]): { left: Point[]; right: Point[] } {
511	  const normals = smoothedNormals(samples);
512	  const left: Point[] = [];
513	  const right: Point[] = [];
514	  for (let i = 0; i < samples.length; i++) {
515	    const half = samples[i].w / 2;
516	    left.push({ x: samples[i].x + normals[i].x * half, y: samples[i].y + normals[i].y * half });
517	    right.push({ x: samples[i].x - normals[i].x * half, y: samples[i].y - normals[i].y * half });
518	  }
519	  return { left, right };
520	}
521	
522	function smoothedNormals(samples: Sample[]): Point[] {
523	  const raw = rawNormals(samples);
524	  if (raw.length <= 2) return raw;
525	  const smoothed: Point[] = new Array(raw.length);
526	  smoothed[0] = raw[0];
527	  smoothed[raw.length - 1] = raw[raw.length - 1];
528	  for (let i = 1; i < raw.length - 1; i++) {
529	    const nx = raw[i - 1].x + raw[i].x + raw[i + 1].x;
530	    const ny = raw[i - 1].y + raw[i].y + raw[i + 1].y;
531	    const len = Math.hypot(nx, ny) || 1;
532	    smoothed[i] = { x: nx / len, y: ny / len };
533	  }
534	  return smoothed;
535	}
536	
537	function rawNormals(samples: Sample[]): Point[] {
538	  const normals: Point[] = [];
539	  for (let i = 0; i < samples.length; i++) {
540	    const prev = samples[i - 1] ?? samples[i];
541	    const next = samples[i + 1] ?? samples[i];
542	    const tx = next.x - prev.x;
543	    const ty = next.y - prev.y;
544	    const len = Math.hypot(tx, ty) || 1;
545	    normals.push({ x: -ty / len, y: tx / len });
546	  }
547	  return normals;
548	}
549	
550	function distance(a: Point, b: Point): number {
551	  return Math.hypot(a.x - b.x, a.y - b.y);
552	}
553	
554	function clamp(v: number, lo: number, hi: number): number {
555	  return v < lo ? lo : v > hi ? hi : v;
556	}
557	
558	function syncCanvasSize() {
559	  const w = window.innerWidth;
560	  const h = window.innerHeight;
561	  svg.setAttribute('viewBox', `0 0 ${w} ${h}`);
562	  svg.setAttribute('width', String(w));
563	  svg.setAttribute('height', String(h));
564	}
565	
566	function clearAll() {
567	  pushHistory();
568	  deselect();
569	  state.strokes = [];
570	  while (svg.firstChild) svg.removeChild(svg.firstChild);
571	}
572	
573	function pushHistory() {
574	  undoStack.push(snapshot());
575	  if (undoStack.length > MAX_HISTORY) undoStack.shift();
576	  redoStack.length = 0;
577	  updateHistoryButtons();
578	}
579	
580	function undo() {
581	  const snap = undoStack.pop();
582	  if (!snap) return;
583	  redoStack.push(snapshot());
584	  restore(snap);
585	  updateHistoryButtons();
586	}
587	
588	function redo() {
589	  const snap = redoStack.pop();
590	  if (!snap) return;
591	  undoStack.push(snapshot());
592	  restore(snap);
593	  updateHistoryButtons();
594	}
595	
596	function updateHistoryButtons() {
597	  undoBtn.disabled = undoStack.length === 0;
598	  redoBtn.disabled = redoStack.length === 0;
599	}
600	
601	function snapshot(): Snapshot {
602	  return state.strokes.map((s) => ({
603	    color: s.color,
604	    renderMode: s.renderMode,
605	    samples: s.samples.map((p) => ({ x: p.x, y: p.y, w: p.w })),
606	  }));
607	}
608	
609	function restore(snap: Snapshot) {
610	  deselect();
611	  state.strokes = [];
612	  while (svg.firstChild) svg.removeChild(svg.firstChild);
613	  for (const data of snap) {
614	    const el = document.createElementNS(SVG_NS, 'path');
615	    el.setAttribute('fill', data.color);
616	    const stroke: Stroke = {
617	      color: data.color,
618	      samples: data.samples,
619	      el,
620	      renderMode: data.renderMode,
621	    };
622	    el.setAttribute('d', strokeToPathD(stroke));
623	    svg.appendChild(el);
624	    state.strokes.push(stroke);
625	  }
626	}
627	
628	function exportSvg() {
629	  const clone = svg.cloneNode(true) as SVGSVGElement;
630	  clone.removeAttribute('id');
631	  clone.setAttribute('xmlns', SVG_NS);
632	  clone.querySelector('#handles')?.remove();
633	  triggerDownload(
634	    new Blob([clone.outerHTML], { type: 'image/svg+xml' }),
635	    `painting-${Date.now()}.svg`,
636	  );
637	}
638	
639	function saveFile() {
640	  const data = { version: FILE_VERSION, strokes: snapshot() };
641	  triggerDownload(
642	    new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' }),
643	    `painting-${Date.now()}.json`,
644	  );
645	}
646	
647	function loadFile() {
648	  const input = document.createElement('input');
649	  input.type = 'file';
650	  input.accept = 'application/json,.json';
651	  input.addEventListener('change', () => {
652	    const file = input.files?.[0];
653	    if (!file) return;
654	    file.text().then(loadFromText).catch(reportLoadError);
655	  });
656	  input.click();
657	}
658	
659	function loadFromText(text: string) {
660	  try {
661	    const data = JSON.parse(text) as unknown;
662	    const snap = migrate(data);
663	    undoStack.length = 0;
664	    redoStack.length = 0;
665	    restore(snap);
666	    updateHistoryButtons();
667	  } catch (err) {
668	    reportLoadError(err);
669	  }
670	}
671	
672	function migrate(data: unknown): Snapshot {
673	  if (!data || typeof data !== 'object') throw new Error('file is not a JSON object');
674	  const obj = data as { version?: unknown; strokes?: unknown };
675	  if (obj.version !== 1) throw new Error(`unsupported file version: ${String(obj.version)}`);
676	  if (!Array.isArray(obj.strokes)) throw new Error('strokes field is missing or not an array');
677	  return obj.strokes.map(parseStrokeV1);
678	}
679	
680	function parseStrokeV1(s: unknown): Snapshot[number] {
681	  if (!s || typeof s !== 'object') throw new Error('stroke must be an object');
682	  const obj = s as { color?: unknown; renderMode?: unknown; samples?: unknown };
683	  if (typeof obj.color !== 'string') throw new Error('stroke.color must be a string');
684	  if (obj.renderMode !== 'catmull' && obj.renderMode !== 'quadratic') {
685	    throw new Error(`unknown renderMode: ${String(obj.renderMode)}`);
686	  }
687	  if (!Array.isArray(obj.samples)) throw new Error('stroke.samples must be an array');
688	  return {
689	    color: obj.color,
690	    renderMode: obj.renderMode,
691	    samples: obj.samples.map(parseSampleV1),
692	  };
693	}
694	
695	function parseSampleV1(s: unknown): Sample {
696	  if (!s || typeof s !== 'object') throw new Error('sample must be an object');
697	  const obj = s as { x?: unknown; y?: unknown; w?: unknown };
698	  if (typeof obj.x !== 'number' || typeof obj.y !== 'number' || typeof obj.w !== 'number') {
699	    throw new Error('sample fields x, y, w must be numbers');
700	  }
701	  return { x: obj.x, y: obj.y, w: obj.w };
702	}
703	
704	function reportLoadError(err: unknown) {
705	  alert(`Failed to load: ${err instanceof Error ? err.message : String(err)}`);
706	}
707	
708	function triggerDownload(blob: Blob, filename: string) {
709	  const url = URL.createObjectURL(blob);
710	  const a = document.createElement('a');
711	  a.href = url;
712	  a.download = filename;
713	  document.body.appendChild(a);
714	  a.click();
715	  document.body.removeChild(a);
716	  URL.revokeObjectURL(url);
717	}
